"Here is a method in Java to convert a string to title case while handling exception words:

```java
public class TitleCaseConverter {

    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        // Capitalize the first letter
        char firstChar = input.charAt(0);
        String capitalizedFirstLetter = Character.toString(firstChar) + input.substring(1).toLowerCase();

        // Process remaining characters
        String result = capitalizedFirstLetter;

        for (int i = 1; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            // Check if current character is a space
            if (currentChar == ' ') {
                // Skip space
                continue;
            }

            // Check if current character is a letter
            if (Character.isLetter(currentChar)) {
                // Check if it's an exception word
                if (ExceptionWordsContains(currentChar, EXCEPTION_WORDS)) {
                    // Skip capitalization
                    result += currentChar;
                } else {
                    // Capitalize if it's not a space and not an exception word
                    result += Character.toUpperCase(currentChar);
                }
            } else {
                // Non-letter character, leave as is
                result += currentChar;
            }
        }

        return result;
    }

    private static boolean ExceptionWordsContains(char character, List<String> exceptionWords) {
        for (String word : exceptionWords) {
            if (word.length() == 1 && Character.toString(character).equals(word)) {
                return true;
            }
        }
        return false;
    }
}
